module asyn_fifo #(
    parameter	WIDTH = 8,
    parameter 	DEPTH = 16,
    parameter ADDR_WIDTH = $clog2(DEPTH)
) (
    input 					wclk,
    input 					rclk,
    input 					wrstn,
    input					rrstn,
    input 					winc,
    input 			 		rinc,
    input 		[WIDTH-1:0]	wdata,
    output wire				wfull,
    output wire				rempty,
    output wire [WIDTH-1:0]	rdata
);

    reg [3:0] waddr_bin, raddr_bin;
    reg [3:0] wptr, rptr;
    reg [3:0] wptr_buff, rptr_buff;
    wire wen, ren;

    assign wfull = (wptr == {~rptr_buff[3], rptr_buff[2:0]});
    assign rempty = (rptr == wptr_syn);

    assign wen = winc && !wfull;
    assign ren = rinc && !rempty;

    always @(posedge wclk or negedge wrstn) begin
        if (!wrstn) begin
            waddr_bin <= 0;
        end else if (winc) begin
            waddr_bin <= waddr_bin + 1;
        end
    end

    always @(posedge rclk or negedge rrstn) begin
        if (!rrstn) begin
            raddr_bin <= 0;
        end else if (rinc) begin
            raddr_bin <= raddr_bin + 1;
        end
    end

    always @(*) begin
        wptr = {waddr_bin[3], ^waddr_bin[2:0]};
        rptr = {raddr_bin[3], ^raddr_bin[2:0]};
    end

    always @(posedge wclk or negedge wrstn) begin
        if (!wrstn) begin
            wptr_buff <= 0;
        end else begin
            wptr_buff <= wptr;
        end
    end

    always @(posedge rclk or negedge rrstn) begin
        if (!rrstn) begin
            rptr_buff <= 0;
        end else begin
            rptr_buff <= rptr;
        end
    end

    dual_port_RAM #( .ADDR_WIDTH(4), .DATA_WIDTH(8)) ram_inst (
        .wclk(wclk),
        .wenc(wen),
        .waddr(waddr_bin[3:0]),
        .wdata(wdata[7:0]),
        .rclk(rclk),
        .renc(ren),
        .raddr(raddr_bin[3:0]),
        .rdata(rdata[7:0])
    );

endmodule

module dual_port_RAM #(parameter DEPTH = 16,  parameter WIDTH = 8)
(
	 input wclk	,
	 input wenc	,
	 input [$clog2(DEPTH)-1:0] waddr  ,
	 input [WIDTH-1:0] wdata ,
	 input rclk	,
	 input renc	,
	 input [$clog2(DEPTH)-1:0] raddr ,
	 output reg [WIDTH-1:0] rdata 		
);

reg [WIDTH-1:0] RAM_MEM [0:DEPTH-1];

always @(posedge wclk) begin
	if(wenc)
		RAM_MEM[waddr] <= wdata;
end 

always @(posedge rclk) begin
	if(renc)
		rdata <= RAM_MEM[raddr];
end 

endmodule
